WITH latest_enrichment AS ( SELECT DISTINCT ON (external_place_id) id, external_place_id FROM preference.place_tag_enrichments WHERE provider = 'KTO' AND status = 'SUCCEEDED' AND external_place_id IN
#{placeId}
ORDER BY external_place_id, enriched_at DESC, updated_at DESC ) SELECT latest.external_place_id, tag.display_name, selected.rank_order FROM latest_enrichment latest JOIN preference.place_tag_enrichment_tags selected ON selected.enrichment_id = latest.id JOIN preference.preference_tags tag ON tag.id = selected.tag_id ORDER BY latest.external_place_id, selected.rank_order
